--* NOTES: CHI MAP DUOC 47.62% RECORD BUREAU BALANCE

WITH BUREAU_DETAIL_1 AS (
    SELECT 
        *,
        LAG(b.DAYS_CREDIT, 1) OVER (PARTITION BY b.SK_ID_CURR ORDER BY b.DAYS_CREDIT ASC) AS LAG_DAYS_CREDIT,
        CASE WHEN CREDIT_TYPE NOT IN ('Microloan', 'Mortgage', 'Car loan', 'Credit card', 'Consumer credit') THEN 'Others' ELSE CREDIT_TYPE END AS CREDIT_TYPE_TRANS
    FROM dbo.bureau b
),

BUREAU_DETAIL AS (
    SELECT
		SK_ID_CURR,

		COUNT(CREDIT_ACTIVE) OVER (PARTITION BY SK_ID_CURR) AS COUNT_CREDIT_STATUS_ALL,
		SUM(CASE WHEN CREDIT_ACTIVE = 'Active' THEN 1 ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS COUNT_CREDIT_STATUS_ACTIVE,
		SUM(CASE WHEN CREDIT_ACTIVE IN ('Bad debt', 'Sold') THEN 1 ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS COUNT_CREDIT_STATUS_BADDEBT,
		MIN(DAYS_CREDIT) OVER (PARTITION BY SK_ID_CURR) AS INIT_CREDIT_INQ_DAYS,
		MAX(DAYS_CREDIT) OVER (PARTITION BY SK_ID_CURR) AS LAST_CREDIT_INQ_DAYS,
		AVG(CAST(DAYS_CREDIT AS FLOAT)) OVER (PARTITION BY SK_ID_CURR) AS MEAN_CREDIT_INQ_DAYS,
		MIN(CREDIT_DAY_OVERDUE) OVER (PARTITION BY SK_ID_CURR) AS MIN_DPD,
		MAX(CREDIT_DAY_OVERDUE) OVER (PARTITION BY SK_ID_CURR) AS MAX_DPD,
		AVG(CAST(CREDIT_DAY_OVERDUE AS FLOAT)) OVER (PARTITION BY SK_ID_CURR) AS MEAN_DPD,
		SUM(CNT_CREDIT_PROLONG) OVER (PARTITION BY SK_ID_CURR) AS COUNT_PROLONGED_LIFETIME,
		SUM(CASE WHEN CNT_CREDIT_PROLONG > 0 THEN 1 ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS IS_PROLONGED,
		MIN(DAYS_CREDIT_UPDATE) OVER (PARTITION BY SK_ID_CURR) AS MIN_DAYS_CREDIT_UPDATE,
		MAX(DAYS_CREDIT_UPDATE) OVER (PARTITION BY SK_ID_CURR) AS MAX_DAYS_CREDIT_UPDATE,
		AVG(CAST(DAYS_CREDIT_UPDATE AS FLOAT)) OVER (PARTITION BY SK_ID_CURR) AS MEAN_DAYS_CREDIT_UPDATE,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_MICROLOAN_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_MORTGAGE_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CAR_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CC_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CONSUMER_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_OTHERS_C1,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_MICROLOAN_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_MORTGAGE_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CAR_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CC_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CONSUMER_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_OTHERS_C2,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_MICROLOAN_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_MORTGAGE_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CAR_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CC_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CONSUMER_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_OTHERS_C3,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_MICROLOAN_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_MORTGAGE_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CAR_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CC_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_CONSUMER_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_MAX_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_MAX_OVERDUE_OTHERS_C4,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_MICROLOAN_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_MORTGAGE_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CAR_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CC_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CONSUMER_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OTHERS_C1,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_MICROLOAN_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_MORTGAGE_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CAR_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CC_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CONSUMER_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OTHERS_C2,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_MICROLOAN_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_MORTGAGE_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CAR_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CC_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CONSUMER_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OTHERS_C3,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_MICROLOAN_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_MORTGAGE_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CAR_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CC_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_CONSUMER_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OTHERS_C4,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_MICROLOAN_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_MORTGAGE_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_CAR_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_CC_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_CONSUMER_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_OTHERS_C1,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_MICROLOAN_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_MORTGAGE_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_CAR_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_DEBT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_DEBT_CC_C2,
