		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM_LIMIT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_LIMIT_CAR_C4,
