		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM_LIMIT ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_LIMIT_OTHERS_C4,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_MICROLOAN_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_MORTGAGE_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CAR_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CC_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CONSUMER_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_OTHERS_C1,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_MICROLOAN_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_MORTGAGE_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CAR_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CC_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CONSUMER_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_OTHERS_C2,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_MICROLOAN_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_MORTGAGE_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CAR_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CC_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CONSUMER_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_OTHERS_C3,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_MICROLOAN_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_MORTGAGE_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CAR_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CC_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_CONSUMER_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_CREDIT_SUM_OVERDUE ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_CREDIT_SUM_OVERDUE_OTHERS_C4,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_MICROLOAN_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_MORTGAGE_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CAR_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CC_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CONSUMER_C1,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 1' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_OTHERS_C1,

		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_MICROLOAN_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_MORTGAGE_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CAR_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CC_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CONSUMER_C2,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 2' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_OTHERS_C2,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_MICROLOAN_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_MORTGAGE_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CAR_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CC_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CONSUMER_C3,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 3' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_OTHERS_C3,
		
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Microloan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_MICROLOAN_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Mortgage' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_MORTGAGE_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Car loan' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CAR_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Credit card' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CC_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Consumer credit' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_CONSUMER_C4,
		SUM(CASE WHEN CREDIT_TYPE_TRANS = 'Others' AND CREDIT_CURRENCY = 'currency 4' THEN AMT_ANNUITY ELSE 0 END) OVER (PARTITION BY SK_ID_CURR) AS AMT_ANNUITY_OTHERS_C4

    FROM BUREAU_DETAIL_1
),

MAP_B_1 AS (
    SELECT 
        *,
        CAST(COUNT_CREDIT_STATUS_ACTIVE AS FLOAT) / NULLIF(COUNT_CREDIT_STATUS_ALL, 0) AS RATE_ACTIVE,
        CAST(COUNT_CREDIT_STATUS_BADDEBT AS FLOAT) / NULLIF(COUNT_CREDIT_STATUS_ALL, 0) AS RATE_BADDEBT
    FROM BUREAU_DETAIL
),

MAP_B AS (
	SELECT DISTINCT * FROM MAP_B_1
)

SELECT * FROM dbo.application_train ATR
LEFT JOIN MAP_B ON ATR.SK_ID_CURR = MAP_B.SK_ID_CURR


